/**
 * Official Type definitions for LemonadeJS plugins
 * https://lemonadejs.net
 * Definitions: https://github.com/DefinitelyTyped/DefinitelyTyped
 */

declare function Schedule(el: HTMLElement, options?: Schedule.Options): Schedule.Instance;

declare namespace Schedule {

    interface Event {
        /** Event type */
        type: string | null;
        /** Event title */
        title: string;
        /** Start time in HH:MM format */
        start: string;
        /** End time in HH:MM format */
        end?: string;
        /** Guests list */
        guests?: string;
        /** Location */
        location?: string;
        /** Description */
        description?: string;
        /** Hex color */
        color: string;
        /** Event is readonly */
        readonly?: boolean;
        /** Guid identification */
        guid: string;
        /** Date in ISO format (YYYY-MM-DD) - used when weekly is false */
        date?: string;
        /** Day of the week (0-6, Sunday is 0) - used when weekly is true */
        weekday?: number;
        /** Visible **/
        visible?: boolean;
        /** Warning border **/
        warning?: boolean;
        /** Cached DOM element reference (assigned at render time) */
        el?: HTMLElement;
    }

    interface Options {
        /** Schedule view type. Default: 'week' */
        type?: 'week' | 'day' | 'weekdays';
        /** Weekly Schedule. No date associated to a column, just the day of the week. Default: false */
        weekly?: boolean;
        /** Initial Date in ISO format (YYYY-MM-DD) */
        value?: string;
        /** Array of events */
        data?: Event[];
        /** Grid time interval in minutes. Default: 15 minutes */
        grid?: number;
        /** Accept time overlap between events. Default: false */
        overlap?: boolean;
        /** Valid time range [startTime, endTime] in HH:MM format */
        validRange?: string[];
        /** Read-only time range. Single range: ['08:00', '18:00'] or multiple ranges: [['00:00', '08:00'], ['18:00', '23:59']] */
        readOnlyRange?: string[] | string[][];
        /** On before create events */
        onbeforecreate?: (self: Instance, events: Event | Event[], e?: MouseEvent) => boolean | void;
        /** On create events */
        oncreate?: (self: Instance, events: Event | Event[], e?: MouseEvent) => void;
        /** On before insert a new event on the board */
        onbeforeinsert?: (self: Instance, event: Event) => Event | boolean | void;
        /** On double-click event */
        ondblclick?: (self: Instance, event: Event) => void;
        /** On edition event - triggered when an event is being edited (double click or after creation) */
        onedition?: (self: Instance, event: Event) => void;
        /** On delete event */
        ondelete?: (self: Instance, event: Event) => void;
        /** On before change event - return false to cancel a drag/resize change to an event */
        onbeforechangeevent?: (self: Instance, state: object) => boolean | void;
        /** On change event properties */
        onchangeevent?: (self: Instance, event: Event, oldValue: Partial<Event>, newValue: Partial<Event>) => void;
        /** Fires before a data mutation (update / delete / setData). Return false to cancel. */
        onbeforechange?: (self: Instance, state: { action: 'updateEvent' | 'deleteEvents' | 'setData'; [key: string]: any }) => boolean | void;
        /** On change - fires after data mutations (update / delete / setData / interactive create) */
        onchange?: (self: Instance) => void;
        /** On error */
        onerror?: (self: Instance, message: string) => void;
    }

    interface Instance {
        /** Schedule view type */
        type: 'week' | 'day' | 'weekdays';
        /** Weekly Schedule mode */
        weekly: boolean;
        /** Current date value in ISO format */
        value: string;
        /** Array of events */
        data: Event[];
        /** Grid time interval in minutes */
        grid: number;
        /** Accept time overlap between events */
        overlap: boolean;
        /** Valid time range */
        validRange?: string[];
        /** Read-only time range. Single range: ['08:00', '18:00'] or multiple ranges: [['00:00', '08:00'], ['18:00', '23:59']] */
        readOnlyRange?: string[] | string[][];
        /** The root element */
        el: HTMLElement;
        /** The tbody element holding all time-row cells */
        tbody: HTMLTableSectionElement;
        /** Header row entries (one per visible column) */
        headers: Array<{ day: string; weekday: number; value: string; selected: boolean; el: HTMLElement }>;
        /** Element used to render the current-time pointer */
        pointer: HTMLElement;
        /** Add one or more events to the schedule */
        addEvents: (events: Event | Event[], e?: MouseEvent) => Event[] | false;
        /** Update an event by guid or reference */
        updateEvent: (guidOrEvent: string | Event, newValue: Partial<Event>) => void | false;
        /** Delete one or more events */
        deleteEvents: (events: Event | Event[] | string | string[]) => void;
        /** Reset selection */
        resetSelection: (e?: MouseEvent) => void;
        /** Set valid time range */
        setRange: (range: string[]) => void;
        /** Set read-only time range. Single range: ['08:00', '18:00'] or multiple ranges: [['00:00', '08:00'], ['18:00', '23:59']] */
        setReadOnly: (range: string[] | string[][]) => void;
        /** Get all events data */
        getData: () => Event[];
        /** Set events data */
        setData: (data: Event[]) => void;
        /** Get event DOM element by guid. Returns null if not found. */
        getEvent: (guid: string) => HTMLElement | null;
        /** Render the schedule */
        render: () => void;
        /** Undo last change */
        undo: () => void;
        /** Redo last undone change */
        redo: () => void;
        /** Navigate to next period (day or week depending on type) */
        next: () => void;
        /** Navigate to previous period (day or week depending on type) */
        prev: () => void;
        /** Navigate to today's date */
        today: () => void;
    }
}

export default Schedule;
